<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Spreadsheet</title>
<style>
body{font-family:sans-serif;margin:0;padding:20px;background:#f4f4f4;}
table{border-collapse:collapse;user-select:none;}
th,td{border:1px solid #999;padding:2px 5px;text-align:center;}
th{background:#ddd;}
input{width:100%;box-sizing:border-box;border:none;font-family:sans-serif;font-size:14px;}
input:focus{outline:2px solid #4a90e2;}
#controls{margin-top:10px;}
textarea{width:100%;height:120px;margin-top:5px;box-sizing:border-box;font-family:monospace;}
</style>
</head>
<body>
<table id="grid">
  <thead><tr><th></th><!-- column headers -->
    <script>for(let c=0;c<10;c++)document.write('<th>'+String.fromCharCode(65+c)+'</th>');</script>
  </tr></thead>
  <tbody>
    <script>
      for(let r=1;r<=10;r++){
        document.write('<tr><th>'+r+'</th>');
        for(let c=0;c<10;c++){
          const id='cell-'+String.fromCharCode(65+c)+r;
          document.write('<td><input type="text" id="'+id+'" value="" data-id="'+id+'"></td>');
        }
        document.write('</tr>');
      }
    </script>
  </tbody>
</table>

<div id="controls">
  <button id="export">Export CSV</button>
  <textarea id="csv" readonly></textarea>
</div>

<script>
const cells=document.querySelectorAll('input[data-id]');
const cellMap={};
cells.forEach(inp=>{cellMap[inp.dataset.id]=inp;});

function setCell(id, text){
  const inp=cellMap[id];
  if(!inp)return;
  inp.value=text;
  recompute();
}
function getCellDisplay(id){return cellMap[id].dataset.display||'';}
function getCellRaw(id){return cellMap[id].value;}

const sheet={set:setCell,get:getCellDisplay,raw:getCellRaw};

window.sheet=sheet;

function recompute(){
  const cache={};
  const cycleSet=new Set();
  function evalCell(id){
    if(cache.hasOwnProperty(id)) return cache[id];
    const inp=cellMap[id];
    const raw=inp.value.trim();
    if(raw===''){cache[id]='';return '';}
    if(!raw.startsWith('=')){
      cache[id]=raw;
      return raw;
    }
    // formula
    let expr=raw.slice(1);
    // replace cell refs
    expr=expr.replace(/[A-J](?:[1-9]|10)/g,match=>{
      const refId='cell-'+match;
      if(refId===id){cycleSet.add(id);return '0';}
      const val=evalCell(refId);
      if(val==='#CYCLE'){cycleSet.add(id);return '0';}
      if(val==='#ERR'){cycleSet.add(id);return '0';}
      return isNaN(Number(val))?0:Number(val);
    });
    try{
      // safe eval
      const result=Function('return '+expr)();
      cache[id]=isFinite(result)?String(result):'#ERR';
    }catch(e){
      cache[id]='#ERR';
    }
    return cache[id];
  }

  Object.keys(cellMap).forEach(id=>evalCell(id));

  // mark cycles
  if(cycleSet.size>0){
    cycleSet.forEach(id=>{
      const inp=cellMap[id];
      const raw=inp.value.trim();
      if(raw.startsWith('=')){
        cache[id]='#CYCLE';
      }
    });
  }

  Object.keys(cellMap).forEach(id=>{
    const disp=cache[id];
    cellMap[id].dataset.display=disp;
    // update display if not editing
    if(document.activeElement!==cellMap[id]){
      cellMap[id].value=disp;
    }
  });
}

cells.forEach(inp=>{
  inp.addEventListener('focus',e=>{e.target.value=e.target.dataset.raw||'';});
  inp.addEventListener('blur',e=>{
    e.target.dataset.raw=e.target.value;
    recompute();
  });
  inp.addEventListener('keydown',e=>{
    if(e.key==='Enter'){e.preventDefault();e.target.blur();}
  });
});

document.getElementById('export').addEventListener('click',()=>{
  const rows=[];
  for(let r=1;r<=10;r++){
    const row=[];
    for(let c=0;c<10;c++){
      const id='cell-'+String.fromCharCode(65+c)+r;
      row.push(cellMap[id].dataset.display||'');
    }
    rows.push(row.join(','));
  }
  document.getElementById('csv').value=rows.join('\n');
});

recompute();
</script>
</body>
</html>
